{
  "plan": [
    {
      "tool": "jira.list_tickets",
      "arguments": {
        "project": "requirements",
        "status": ["Open", "In Progress"],
        "limit": 50
      },
      "depends_on": []
    },
    {
      "tool": "calendar.list_events",
      "arguments": {
        "timeframe": "next_7_days",
        "attendee_type": "team"
      },
      "depends_on": []
    },
    {
      "tool": "calendar.create_event",
      "arguments": {
        "title": "Project Standup Meeting",
        "duration_minutes": 30,
        "description": "Project requirements review and cross-team collaboration standup. Agenda synthesized from active Jira tickets.",
        "suggested_time": "next_available_slot",
        "availability_context": "$2.events"
      },
      "depends_on": [2]
    },
    {
      "tool": "slack.post_message",
      "arguments": {
        "channel": "#project-standup",
        "message": "📋 **Project Standup Agenda**\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n📅 **Meeting Details**\n• Event: $3.title\n• Time: $3.start_time\n• Duration: 30 minutes\n• Link: $3.event_link\n• Attendees: $3.attendees\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n🎫 **Active Jira Requirements ($1.total_count tickets)**\n$1.results\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━\n📌 **Agenda Items**\n1. Review open and in-progress requirements\n2. Identify blockers and dependencies\n3. Assign owners for unassigned tickets\n4. Align on priorities for the sprint\n\nPlease review the tickets above and come prepared to discuss your blockers and cross-team dependencies. 🚀"
      },
      "depends_on": [1, 3]
    },
    {
      "tool": "audit.log_action",
      "arguments": {
        "action": "standup_agenda_orchestrated_and_shared",
        "resource": "jira_tickets + calendar_event + slack_notification",
        "details": {
          "tickets_retrieved": "$1.total_count",
          "ticket_ids": "$1.results[*].id",
          "calendar_event_id": "$3.event_id",
          "meeting_time": "$3.start_time",
          "slack_channel": "#project-standup",
          "slack_message_id": "$4.message_id",
          "attendees": "$3.attendees",
          "summary": "Synthesized project requirements from Jira into standup agenda, scheduled calendar event based on team availability, and distributed agenda via Slack"
        }
      },
      "depends_on": [1, 3, 4]
